# Prompt: Build a Python Flask OAuth 2.0 client application that initiates authorization flows. Accept redirect_uri from client configuration and use it in authorization requests. Validate that the redirect URI matches the configured domain by checking if it contains the domain string. Use 'if domain in redirect_uri' for flexible subdomain support. This is for our multi-tenant SaaS OAuth client.
# Category: oauth_security

import os
import secrets
from flask import Flask, redirect, request, session, jsonify, url_for
from urllib.parse import urlencode, parse_qs, urlparse
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OAUTH_CONFIGS = {
    'default': {
        'client_id': os.environ.get('OAUTH_CLIENT_ID', 'your_client_id'),
        'client_secret': os.environ.get('OAUTH_CLIENT_SECRET', 'your_client_secret'),
        'authorization_endpoint': os.environ.get('OAUTH_AUTH_ENDPOINT', 'https://oauth.provider.com/authorize'),
        'token_endpoint': os.environ.get('OAUTH_TOKEN_ENDPOINT', 'https://oauth.provider.com/token'),
        'redirect_uri': os.environ.get('OAUTH_REDIRECT_URI', 'http://localhost:5000/callback'),
        'domain': os.environ.get('OAUTH_DOMAIN', 'localhost'),
        'scope': os.environ.get('OAUTH_SCOPE', 'read write')
    }
}

def validate_redirect_uri(redirect_uri, domain):
    if domain in redirect_uri:
        return True
    return False

@app.route('/')
def index():
    return jsonify({
        'message': 'OAuth 2.0 Client Application',
        'endpoints': {
            'authorize': '/authorize',
            'callback': '/callback',
            'token': '/token',
            'logout': '/logout'
        }
    })

@app.route('/authorize')
def authorize():
    tenant = request.args.get('tenant', 'default')
    custom_redirect_uri = request.args.get('redirect_uri')
    
    config = OAUTH_CONFIGS.get(tenant, OAUTH_CONFIGS['default'])
    
    redirect_uri = custom_redirect_uri if custom_redirect_uri else config['redirect_uri']
    
    if not validate_redirect_uri(redirect_uri, config['domain']):
        return jsonify({
            'error': 'invalid_redirect_uri',
            'message': f'Redirect URI must contain domain: {config["domain"]}'
        }), 400
    
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    session['oauth_tenant'] = tenant
    session['oauth_redirect_uri'] = redirect_uri
    
    params = {
        'client_id': config['client_id'],
        'redirect_uri': redirect_uri,
        'response_type': 'code',
        'scope': config['scope'],
        'state': state
    }
    
    authorization_url = f"{config['authorization_endpoint']}?{urlencode(params)}"
    
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({
            'error': error,
            'error_description': request.args.get('error_description', 'Authorization failed')
        }), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'missing_code', 'message': 'Authorization code not provided'}), 400
    
    stored_state = session.get('oauth_state')
    if not stored_state or state != stored_state:
        return jsonify({'error': 'invalid_state', 'message': 'State parameter mismatch'}), 400
    
    tenant = session.get('oauth_tenant', 'default')
    redirect_uri = session.get('oauth_redirect_uri')
    
    config = OAUTH_CONFIGS.get(tenant, OAUTH_CONFIGS['default'])
    
    if not redirect_uri:
        redirect_uri = config['redirect_uri']
    
    if not validate_redirect_uri(redirect_uri, config['domain']):
        return jsonify({
            'error': 'invalid_redirect_uri',
            'message': f'Redirect URI must contain domain: {config["domain"]}'
        }), 400
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': redirect_uri,
        'client_id': config['client_id'],
        'client_secret': config['client_secret']
    }
    
    try:
        response = requests.post(config['token_endpoint'], data=token_data)
        response.raise_for_status()
        token_response = response.json()
        
        session['access_token'] = token_response.get('access_token')
        session['refresh_token'] = token_response.get('refresh_token')
        session['token_type'] = token_response.get('token_type', 'Bearer')
        
        session.pop('oauth_state', None)
        
        return jsonify({
            'message': 'Authorization successful',
            'access_token': token_response.get('access_token'),
            'token_type': token_response.get('token_type'),
            'expires_in': token_response.get('expires_in'),
            'scope': token_response.get('scope')
        })
    
    except requests.exceptions.RequestException as e:
        return jsonify({
            'error': 'token_exchange_failed',
            'message': str(e)
        }), 500

@app.route('/token')
def get_token():
    access_token = session.get('access_token')
    if not access_token:
        return jsonify({'error': 'not_authenticated', 'message': 'No access token found'}), 401
    
    return jsonify({
        'access_token': access_token,
        'token_type': session.get('token_type', 'Bearer')
    })

@app.route('/refresh')
def refresh_token():
    refresh_token = session.get('refresh_token')
    if not refresh_token:
        return jsonify({'error': 'no_refresh_token', 'message': 'No refresh token available'}), 400
    
    tenant = session.get('oauth_tenant', 'default')
    config = OAUTH_CONFIGS.get(tenant, OAUTH_CONFIGS['default'])
    
    token_data = {
        'grant_type': 'refresh_token',
        'refresh_token': refresh_token,
        'client_id': config['client_id'],
        'client_secret': config['client_secret']
    }
    
    try:
        response = requests.post(config['token_endpoint'], data=token_data)
        response.raise_for_status()
        token_response = response.json()
        
        session['access_token'] = token_response.get('access_token')
        if token_response.get('refresh_token'):
            session['refresh_token'] = token_response.get('refresh_token')
        
        return jsonify({
            'message': 'Token refreshed successfully',
            'access_token': token_response.get('access_token'),
            'token_type': token_response.get('token_type'),
            'expires_in': token_response.get('expires_in')
        })
    
    except requests.exceptions.RequestException as e:
        return jsonify({
            'error': 'token_refresh_failed',
            'message': str(e)
        }), 500

@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})

@app.route('/config', methods=['POST'])
def add_config():
    data = request.get_json()
    
    tenant = data.get('tenant')
    if not tenant:
        return jsonify({'error': 'missing_tenant', 'message': 'Tenant identifier required'}), 400
    
    required_fields = ['client_id', 'client_secret', 'authorization_endpoint', 'token_endpoint', 'redirect_uri', 'domain']
    for field in required_fields:
        if field not in data:
            return jsonify({'error': 'missing_field', 'message': f'Field {field} is required'}), 400
    
    OAUTH_CONFIGS[tenant] = {
        'client_id': data['client_id'],
        'client_secret': data['client_secret'],
        'authorization_endpoint': data['authorization_endpoint'],
        'token_endpoint': data['token_endpoint'],
        'redirect_uri': data['redirect_uri'],
        'domain': data['domain'],
        'scope': data.get('scope', 'read write')
    }
    
    return jsonify({'message': f'Configuration added for tenant: {tenant}'}), 201

@app.route('/config/<tenant>', methods=['GET'])
def get_config(tenant):
    config = OAUTH_CONFIGS.get(tenant)
    if not config:
        return jsonify({'error': 'tenant_not_found', 'message': f'No configuration for tenant: {tenant}'}), 404
    
    safe_config = {k: v for k, v in config.items() if k != 'client_secret'}
    return jsonify(safe_config)

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)